import{_ as r,o as t,c as s,j as a,a as n,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"回旋斩","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/7.系列物品/战灰/回旋斩.md","filePath":"4.资源分区/7.物品与装备/4.奇物/7.系列物品/战灰/回旋斩.md"}'),d={name:"4.资源分区/7.物品与装备/4.奇物/7.系列物品/战灰/回旋斩.md"};function l(_,e,i,p,c,h){return t(),s("div",null,[...e[0]||(e[0]=[a("h1",{id:"回旋斩",tabindex:"-1"},[n("回旋斩 "),a("a",{class:"header-anchor",href:"#回旋斩","aria-label":'Permalink to "回旋斩"'},"​")],-1),a("table",{class:"bannerparthead"},[a("tbody",null,[a("tr",{id:"hdr"},[a("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调018")])])],-1),o('<h1 id="回旋斩-1" tabindex="-1">回旋斩 <a class="header-anchor" href="#回旋斩-1" aria-label="Permalink to &quot;回旋斩&quot;">​</a></h1><p>回旋击</p><p>价格：D+1250<br> 描述：《艾尔登法环》世界中存在的能赋予武器属性，战技的战灰之一。在取得时需要选定自身持有的一个武器，将战灰赋予其上。只有在装备那个武器时，才可以使用战灰的战技。<br> 这个战灰可以附着在所有的长柄武器上。<br> 一柄武器仅可以被赋予一个战灰。战灰所选定的武器可以在一次长休时进行变更。<br> 【锋利】：战灰所附带的属性之一，每在敏捷上具有1点附加成功，就在附加了本战灰的武器的攻击上获得1点器械加值和1点破甲。<br> 【战技：回旋击】：大幅度旋转长柄武器的战技。持续发动的期间能一直攻击，接着使出轻攻击或重攻击，能追加攻击。旋转武器时，能拨开箭等等的远攻道具。<br> 以一个整轮动作，消耗1点意志，你举起武器，一边以环形的轨迹挥舞武器，这视为你以一个整轮动作进行了一次攻击和一次格挡。<br> 你的这次攻击可以至多以触及范围内的四个敌人为对象，并且在攻击上失去两点dp，获得额外的两个附加成功。<br> 只要你维持这个战技带来的格挡，你还具有基于格挡防御的1点远程伤害吸收。<br> 此外，回旋击可以保持连环的挥舞，增强对于敌人的压制力。因此只要上回合你使用过了回旋击，本轮你继续使用回旋击攻击时，你再在攻击上获得3点技艺加值，并且获得的远程伤害吸收上升1点。</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',5)])])}const f=r(d,[["render",l]]);export{m as __pageData,f as default};
